fn solve(s: String, k: i64) -> String {
    let mut result: Vec<char> = Vec::new();

    for c in s.chars() {
        match c {
            '*' => {
                if !result.is_empty() {
                    result.pop();
                }
            },
            '#' => {
                let len = result.len();
                for i in 0..len {
                    result.push(result[i]);
                }
            },
            '%' => {
                result.reverse();
            },
            _ => {
                result.push(c);
            }
        }
    }

    if k < 0 || k as usize >= result.len() {
        return String::from(".");
    }

    return String::from(result[k as usize]);
}
